int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;

    while (t--) {
        string s;
        cin >> s;

        unordered_map<char, int> freq;
        for (char c : s) {
            freq[c]++;
        }

        int n = s.size();
        long long ans = 0;
        for (int i = 0; i < n; i++) {
            long long curr = 1;
            for (auto& it : freq) {
                curr *= (it.second + 1);
            }

            ans += curr;

            freq[s[i]]--;
            if (freq[s[i]] == 0) {
                freq.erase(s[i]);
            }

            curr = 1;
            for (auto& it : freq) {
                curr *= (it.second + 1);
            }

            ans -= curr;
        }

        cout << ans << '\n';
    }

    return 0;
}

