#include <bits/stdc++.h>
using namespace std;

int main() {
    int t;
    cin >> t;
    while (t--) {
        string s;
        cin >> s;
        int k;
        cin >> k;
        unordered_set<char> st;
        vector<int> f(26, 0);
        for (char c : s) {
            f[c - 'a']++;
        }
        for (int i = 0; i < 26; i++) {
            if (f[i] > 0) {
                st.insert('a' + i);
            }
        }
        if (st.size() < k) {
            cout << 0 << endl;
            continue;
        }
        int ans = INT_MAX;
        for (int mask = 0; mask < (1 << 26); mask++) {
            if (__builtin_popcount(mask) != k) {
                continue;
            }
            int cnt = 0;
            for (char c : s) {
                if ((mask & (1 << (c - 'a'))) > 0) {
                    cnt++;
                }
            }
            ans = min(ans, cnt);
        }
        cout << ans << endl;
    }
    return 0;
}

