const int INF = 1e9 + 7;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;

    while (t--) {
        int n;
        cin >> n;

        vector<int> a(n);
        for (int i = 0; i < n; i++) {
            cin >> a[i];
        }

        vector<int> dp(n + 1, 0);
        dp[1] = a[0];

        for (int i = 2; i <= n; i++) {
            int max_val = -INF;
            for (int j = 1; j * j <= i; j++) {
                if (i % j == 0) {
                    max_val = max(max_val, dp[j]);
                    max_val = max(max_val, dp[i / j]);
                }
            }
            dp[i] = max_val + a[i - 1];
        }

        cout << dp[n] << '\n';
    }

    return 0;
}

