void solve() {
    int64_t n, k;
    cin >> n >> k;
    vector<int64_t> a(n);
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }
    sort(a.begin(), a.end());
    int64_t ans = 0, cnt = 0;
    for (int i = 0; i < n; i++) {
        if (a[i] <= k) {
            ans += k - a[i];
            cnt++;
        } else {
            break;
        }
    }
    for (int i = cnt - 1; i >= 0; i--) {
        int64_t x = k / cnt;
        int64_t y = k / cnt + (k % cnt != 0);
        if (a[i] <= x) {
            ans += y - a[i];
        } else {
            ans += x - a[i];
        }
        cnt--;
    }
    cout << ans << '\n';
}

